INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (7001, 1, "たまには\n協力するのもいいんじゃない？\nあたしも手を貸してあげる", 0, 0.0, 1, 106001, "キャル", "2030/12/17 14:59:59", 7, 0, 1, -363.0, "2015/12/17 15:00:00", 0.0);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (7002, 1, "多くの方と協力して\n戦えるようです\n主さまなら、さぞ\nご活躍なさることでしょう", 0, 0.0, 1, 105901, "コッコロ", "2030/12/17 14:59:59", 7, 0, 1, -363.0, "2015/12/17 15:00:00", 0.0);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (7003, 1, "たくさんの人と一緒に\n協力バトルです！\nがんばりましょう☆", 0, 0.0, 1, 105801, "ペコリーヌ", "2030/12/17 14:59:59", 7, 0, 1, -363.0, "2015/12/17 15:00:00", 0.0);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (10001, 1, "ジュエルを食べ物…\nいえ、貴重品と交換できます！", 0, 0.0, 1, 105801, "ペコリーヌ", "2030/12/17 14:59:59", 10, 0, 1, -363.0, "2015/12/17 15:00:00", 0.0);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (10002, 1, "ジュエルはよく考えて\n使うことね\n無駄遣い厳禁！", 0, 0.0, 1, 106001, "キャル", "2030/12/17 14:59:59", 10, 0, 1, -363.0, "2015/12/17 15:00:00", 0.0);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (10003, 1, "主さまのジュエルで\n貴重な品々を購入できます\nですが、無駄遣いは\n『めっ』でございますよ", 0, 0.0, 1, 105901, "コッコロ", "2030/12/17 14:59:59", 10, 0, 1, -363.0, "2015/12/17 15:00:00", 0.0);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (10004, 1, "ジュエルがあれば\n貴重品と交換できるみたい\n大事に使いましょうね", 0, 0.0, 1, 106401, "シェフィ", "2030/12/17 14:59:59", 10, 2104010, 2, -363.0, "2015/12/17 15:00:00", 0.0);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (12001, 1, "特定の条件を達成すると\n報酬がもらえますよ！\nがんばりましょう♪　", 0, 0.0, 1, 105801, "ペコリーヌ", "2030/12/17 14:59:59", 12, 0, 1, -416.5, "2015/12/17 15:00:00", 0.0);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (13001, 1, "思い出が詰まってるって\nいろいろあったけど\n振り返るのもいいんじゃない？", 0, 0.0, 1, 106001, "キャル", "2030/12/17 14:59:59", 13, 0, 1, -363.0, "2015/12/17 15:00:00", 0.0);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (13002, 1, "主さまとの楽しい日々…\nこちらで何度でも\n思い返しましょう♪", 0, 0.0, 1, 105901, "コッコロ", "2030/12/17 14:59:59", 13, 0, 1, -363.0, "2015/12/17 15:00:00", 0.0);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (13003, 1, "みんなとの大切な思い出が\nたくさん詰まってるのね\n一緒に振り返って、\n心に刻みたいわ", 0, 0.0, 1, 106401, "シェフィ", "2030/12/17 14:59:59", 13, 2104010, 2, -363.0, "2015/12/17 15:00:00", 0.0);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (13004, 1, "女の子との思い出が\nたくさん見られますよ！\nヒューヒュー♪\nモテモテですねー☆", 0, 0.0, 1, 105801, "ペコリーヌ", "2030/12/17 14:59:59", 13, 0, 1, -363.0, "2015/12/17 15:00:00", 0.0);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (14001, 1, "育成に必要なアイテムが\n獲得できるクエストです\nわたくし、主さまのために、\n強くなりますよ", 0, 0.0, 1, 105901, "コッコロ", "2030/12/17 14:59:59", 14, 0, 1, -363.0, "2015/12/17 15:00:00", 0.0);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (14002, 1, "このクエストを攻略すると、\nアイテムが手に入るらしいわ。\nもっと強くなるために、\n一生懸命がんばるわね！", 0, 0.0, 1, 106401, "シェフィ", "2030/12/17 14:59:59", 14, 2104010, 2, -363.0, "2015/12/17 15:00:00", 0.0);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (14003, 1, "このクエストを攻略すれば、\nアイテムがもらえますよ\nたくさん集めて、どんどん\n強くなっちゃいましょう！", 0, 0.0, 1, 105801, "ペコリーヌ", "2030/12/17 14:59:59", 14, 0, 1, -363.0, "2015/12/17 15:00:00", 0.0);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (14004, 1, "クエストを攻略すると、\nアイテムが手に入るんだって\nもらえるものは、\nもらっておきましょ！", 0, 0.0, 1, 106001, "キャル", "2030/12/17 14:59:59", 14, 0, 1, -363.0, "2015/12/17 15:00:00", 0.0);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (15001, 1, "主さま、旅の準備を整えて\nより充実した冒険をいたし\nましょう", 0, 0.0, 1, 105901, "コッコロ", "2030/12/17 14:59:59", 15, 0, 1, -470.0, "2015/12/17 15:00:00", 0.0);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (16001, 1, "ねぇ…クランに加入してみない？\n一人も楽しいけど、みんなと\n一緒も賑やかでいいと思うの", 0, 0.0, 1, 106401, "シェフィ", "2030/12/17 14:59:59", 16, 2104010, 2, -363.0, "2015/12/17 15:00:00", 0.0);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (16002, 1, "クランに加入してみませんか？\nみんなといっしょに冒険した方が、\n楽しいですよ！", 0, 0.0, 1, 105801, "ペコリーヌ", "2030/12/17 14:59:59", 16, 0, 1, -363.0, "2015/12/17 15:00:00", 0.0);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (16003, 1, "クランに入れるらしいわよ\nせっかくだから入ってみたら？\nけっこう楽しいみたいよ♪", 0, 0.0, 1, 106001, "キャル", "2030/12/17 14:59:59", 16, 0, 1, -363.0, "2015/12/17 15:00:00", 0.0);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (16004, 1, "こちらでクランに加入できます\n素敵なクランがたくさんあって、\n目移りしてしまいますね", 0, 0.0, 1, 105901, "コッコロ", "2030/12/17 14:59:59", 16, 0, 1, -363.0, "2015/12/17 15:00:00", 0.0);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (17002, 1, " こちらではクランバトルに\n 参加された仲間のみなさんの\n 活躍を振り返ることができます", 0, 0.0, 1, 105901, "コッコロ", "2030/12/17 14:59:59", 17, 0, 1, -363.0, "2015/12/17 15:00:00", 0.0);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (17004, 1, "模擬戦の戦績もアンタが\n気に入ったものがあれば\n記録しておけるのね", 0, 0.0, 1, 106001, "キャル", "2030/12/17 14:59:59", 25, 0, 1, -363.0, "2015/12/17 15:00:00", 0.0);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (17005, 1, "主さま、今回のクランバトルでの\nご活躍が記録されています\nバトルの参考にいたしましょう", 0, 0.0, 1, 105901, "コッコロ", "2030/12/17 14:59:59", 25, 0, 1, -363.0, "2015/12/17 15:00:00", 0.0);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (17006, 1, "今回のクランバトルの調子は\nどうかしら？\n戦績を見れば、次のバトルに\n活かせるかもしれないわ", 0, 0.0, 1, 106401, "シェフィ", "2030/12/17 14:59:59", 25, 2104010, 2, -363.0, "2015/12/17 15:00:00", 0.0);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (17007, 1, "今回のクランバトルでの戦績を\nおさらいできますよ！\n私にも見せてください☆", 0, 0.0, 1, 105801, "ペコリーヌ", "2030/12/17 14:59:59", 25, 0, 1, -363.0, "2015/12/17 15:00:00", 0.0);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (18001, 1, "ようこそ！\nこちらでは、\nギルドハウスで流れる音楽の\n変更や購入が出来ますよ", 0, 0.0, 1, 190801, "カリン", "2030/12/17 14:59:59", 18, 0, 1, -363.0, "2015/12/17 15:00:00", 0.0);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (18002, 1, "ＢＧＭの変更や購入は、こちらから\nできますよ\n素敵な音楽を、たくさんご用意\nいたしました！", 0, 0.0, 2, 190801, "カリン", "2030/12/17 14:59:59", 18, 0, 1, -363.0, "2015/12/17 15:00:00", 0.0);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (19001, 1, "ギルドハウスの\nＢＧＭを変更できますよ\nあなたの好きな曲、\n私にも聴かせてくださいね", 0, 0.0, 3, 190801, "カリン", "2030/12/17 14:59:59", 19, 0, 1, -470.0, "2015/12/17 15:00:00", 0.0);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (19002, 1, "こちらでは、ＢＧＭの変更が\nできますよ\nどんな曲に変更しますか？\nふふふ、私も楽しみです♪", 0, 0.0, 4, 190801, "カリン", "2030/12/17 14:59:59", 19, 0, 1, -470.0, "2015/12/17 15:00:00", 0.0);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (20001, 1, "こちらでは、ＢＧＭを購入\nすることができますよ\n試聴することもできるので、\nじっくり選んでくださいね", 0, 0.0, 5, 190801, "カリン", "2030/12/17 14:59:59", 20, 0, 1, -470.0, "2015/12/17 15:00:00", 0.0);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (20002, 1, "いらっしゃいませ！\nＢＧＭの購入はこちらです\n素敵な曲がたくさんあって、\n目移りしちゃいますね", 0, 0.0, 6, 190801, "カリン", "2030/12/17 14:59:59", 20, 0, 1, -470.0, "2015/12/17 15:00:00", 0.0);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (21001, 1, "ここで手に入れたアイテムで\n専用装備を作成できるみたいね\nアイテムが集まったら\nさっそく作ってみましょ！", 0, 0.0, 1, 106001, "キャル", "2030/12/17 14:59:59", 21, 0, 1, -363.0, "2015/12/17 15:00:00", 0.0);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (21002, 1, "攻略すると珍しいアイテムが\n手に入りますよ\nこのアイテムで専用装備を\n作成できるようです", 0, 0.0, 1, 105901, "コッコロ", "2030/12/17 14:59:59", 21, 0, 1, -363.0, "2015/12/17 15:00:00", 0.0);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (21003, 1, "専用装備が欲しいなら\nこのクエストに挑戦するといいわ\n集めた素材でもっともっと\n強くなりましょう", 0, 0.0, 1, 106401, "シェフィ", "2030/12/17 14:59:59", 21, 2104010, 2, -363.0, "2015/12/17 15:00:00", 0.0);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (21004, 1, "専用装備の作成に必要な\nアイテムを獲得できますよ\nたくさん集めてどんどん\n強くなりましょう！", 0, 0.0, 1, 105801, "ペコリーヌ", "2030/12/17 14:59:59", 21, 0, 1, -363.0, "2015/12/17 15:00:00", 0.0);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (22001, 1, "投票はこちらです\nあなたが応援したい女の子に\n思いを込めた一票を\nお願いします！", 0, 0.0, 1, 190801, "カリン", "2030/12/17 14:59:59", 22, 0, 1, -430.0, "2015/12/17 15:00:00", 0.0);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (22002, 1, "ようこそ！\nあなたが思いを寄せるのは\nどの女の子ですか？\n応援してあげてくださいね！", 0, 0.0, 2, 190801, "カリン", "2030/12/17 14:59:59", 22, 0, 1, -430.0, "2015/12/17 15:00:00", 0.0);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (23001, 1, "たくさんの投票、\nありがとうございました\n結果発表を楽しみに\n待っていてくださいね！", 0, 0.0, 3, 190801, "カリン", "2030/12/17 14:59:59", 23, 0, 1, -430.0, "2015/12/17 15:00:00", 0.0);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (23002, 1, "ただ今、人気投票の\n集計中です\n結果が出るまでもう少しだけ\nお待ちくださいね", 0, 0.0, 4, 190801, "カリン", "2030/12/17 14:59:59", 23, 0, 1, -430.0, "2015/12/17 15:00:00", 0.0);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (24001, 2, "あなた様が手伝ってくださった\nチョコレートケーキ\n美味しくないはずがありませんわ", 10011, 8.0, 1, 109001, "エリコ（バレンタイン）", "2030/12/17 14:59:59", 24, 0, 1, -385.0, "2019/01/31 12:00:00", 4.08);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (24002, 2, "このような失敗、あなた様が\nするはずありません\nもう一度挑戦してみましょう", 10011, 8.0, 2, 109001, "エリコ（バレンタイン）", "2030/12/17 14:59:59", 24, 0, 1, -385.0, "2019/01/31 12:00:00", 5.0);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (24003, 2, "あなた様のために\n作っているケーキを\nあなた様に手伝っていただく……\nことになるなんて……クスクス", 10011, 8.0, 3, 109001, "エリコ（バレンタイン）", "2030/12/17 14:59:59", 24, 0, 1, -385.0, "2019/01/31 12:00:00", 10.11);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (24004, 2, "あまり気に病む必要はありませんわ\nこれからは私がたっぷりと\n時間をかけて教えて差し上げますから", 10011, 8.0, 4, 109001, "エリコ（バレンタイン）", "2030/12/17 14:59:59", 24, 0, 1, -385.0, "2019/01/31 12:00:00", 4.0);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (24005, 2, "今回は調子が悪かった……のですか？\nあなた様が手伝ってくれたものなら\nわたしはどんなものでも……クスクス", 10011, 8.0, 5, 109001, "エリコ（バレンタイン）", "2030/12/17 14:59:59", 24, 0, 1, -385.0, "2019/01/31 12:00:00", 6.0);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (24006, 1, "あなた様が手がけた\nチョコレートケーキは\n私にとっての宝物……\n侮辱する者は生かしておきませんわ", 10011, 0.0, 6, 109002, "エリコ（バレンタイン）", "2030/12/17 14:59:59", 24, 0, 1, 0.0, "2019/01/31 12:00:00", 0.0);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (24007, 1, "とても素晴らしい出来栄えですわ！\nあなた様にふさわしい\nチョコレートケーキができました", 10011, 0.0, 7, 109002, "エリコ（バレンタイン）", "2030/12/17 14:59:59", 24, 0, 1, 0.0, "2019/01/31 12:00:00", 0.0);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (24008, 1, "私を手伝ってくれたあなた様は\nすでに私の虜……\n甘い世界に誘って差し上げますわ", 10011, 0.0, 8, 109002, "エリコ（バレンタイン）", "2030/12/17 14:59:59", 24, 0, 1, 0.0, "2019/01/31 12:00:00", 0.0);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (24009, 1, "あなた様の愛情\nしかと受け止めました\nこれが……私たちの初めての\n共同作業ですわね……クスクス", 10011, 0.0, 9, 109002, "エリコ（バレンタイン）", "2030/12/17 14:59:59", 24, 0, 1, 0.0, "2019/01/31 12:00:00", 0.0);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (24010, 1, "これは世界一の\nチョコレートケーキですわ\nだって、あなた様が腕によりをかけて\n作ってくださったんですもの", 10011, 0.0, 10, 109002, "エリコ（バレンタイン）", "2030/12/17 14:59:59", 24, 0, 1, 0.0, "2019/01/31 12:00:00", 0.0);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (24011, 2, "上手にできなくて残念だった？\nでも、弟くんの気持ちが嬉しいな\nいつだってお姉ちゃんは\nそばにいるからね♪", 10011, 8.0, 1, 109101, "シズル（バレンタイン）", "2030/12/17 14:59:59", 24, 0, 1, -385.0, "2019/01/31 12:00:00", 2.12);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (24012, 2, "うーん、弟くんには珍しく\n緊張しちゃったのかな？\nもう一度チャレンジしてみる？", 10011, 8.0, 2, 109101, "シズル（バレンタイン）", "2030/12/17 14:59:59", 24, 0, 5, -385.0, "2019/01/31 12:00:00", 4.19);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (24013, 4, "お姉ちゃんのお手伝い、\nよくできました！\nあー、\nまだつまみ食いしちゃダメだぞ！", 10011, 8.0, 3, 109101, "シズル（バレンタイン）", "2030/12/17 14:59:59", 24, 0, 2, -385.0, "2019/01/31 12:00:00", 2.3);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (24014, 1, "見てみて！\nスポンジに綺麗な焼き目がついてるよ\nさっすが弟くんだね！", 10011, 0.0, 4, 109102, "シズル（バレンタイン）", "2030/12/17 14:59:59", 24, 0, 1, 0.0, "2019/01/31 12:00:00", 0.0);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (24015, 2, "まぁまぁ、落ち込まないで\n見た目は……個性的だけど、\n味は絶対美味しいはずだから！", 10011, 8.0, 5, 109101, "シズル（バレンタイン）", "2030/12/17 14:59:59", 24, 0, 5, -385.0, "2019/01/31 12:00:00", 5.23);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (24016, 1, "弟くんみたいな\n可愛いケーキができたよ！\n早く食べてみたいでしょ♪", 10011, 0.0, 6, 109102, "シズル（バレンタイン）", "2030/12/17 14:59:59", 24, 0, 1, 0.0, "2019/01/31 12:00:00", 0.0);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (24017, 2, "あれれ？　弟くん、指に\nチョコレートがくっついてるよ？\nお姉ちゃんが舐めてあげるね、\nはぁむ！", 10011, 8.0, 7, 109101, "シズル（バレンタイン）", "2030/12/17 14:59:59", 24, 0, 1, -385.0, "2019/01/31 12:00:00", 5.01);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (24018, 1, "なかなか上手にできたんじゃない？\nでも弟くんはまだまだできる子！\nお姉ちゃん、信じてるからね", 10011, 0.0, 8, 109102, "シズル（バレンタイン）", "2030/12/17 14:59:59", 24, 0, 1, 0.0, "2019/01/31 12:00:00", 0.0);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (24019, 1, "わぁ～、\nとっても美味しそうにできたね！\n弟くん手慣れてたから\nお姉ちゃん安心して任せられちゃった！", 10011, 0.0, 9, 109102, "シズル（バレンタイン）", "2030/12/17 14:59:59", 24, 0, 1, 0.0, "2019/01/31 12:00:00", 0.0);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (24020, 1, "や～ん、弟くんが手伝ってくれた\nチョコレートケーキ！\nすっごく美味しそうにできたね♪", 10011, 0.0, 10, 109102, "シズル（バレンタイン）", "2030/12/17 14:59:59", 24, 0, 1, 0.0, "2019/01/31 12:00:00", 0.0);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (26001, 1, "ここから先は神聖な場所みたい\nどんなお宝が眠っているのか、\n今から探索するのが楽しみね♪", 0, 0.0, 1, 106401, "シェフィ", "2030/12/17 14:59:59", 26, 2104010, 2, -363.0, "2015/12/17 15:00:00", 0.0);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (26002, 1, "ここから先は神聖な場所\nみたいです！\nどんなお宝が手に入るか\n楽しみですね！", 0, 0.0, 1, 105801, "ペコリーヌ", "2030/12/17 14:59:59", 26, 0, 1, -363.0, "2015/12/17 15:00:00", 0.0);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (26003, 1, "この先は神聖な場所みたい。\n手に入るお宝も並じゃないけど\n気を付けていかないと\n痛い目にあうわよ", 0, 0.0, 1, 106001, "キャル", "2030/12/17 14:59:59", 26, 0, 1, -363.0, "2015/12/17 15:00:00", 0.0);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (26004, 1, "ここから先は神聖な場所\nでございます。\n気を引き締めてお宝の\n調査探索に参りましょう", 0, 0.0, 1, 105901, "コッコロ", "2030/12/17 14:59:59", 26, 0, 1, -363.0, "2015/12/17 15:00:00", 0.0);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (27001, 1, "ここにさらなる力を得るための\nアイテムが眠っている…って\nみんな言ってるわ。ふふっ、\nそれじゃあ挑戦してみましょうか", 0, 0.0, 1, 106401, "シェフィ", "2030/12/17 14:59:59", 27, 2104010, 2, -363.0, "2015/12/17 15:00:00", 0.0);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (27002, 1, "ここにさらなる力を得るための\nアイテムが眠っているみたい\nです！　どこから挑戦するか\n迷っちゃいますね！", 0, 0.0, 1, 105801, "ペコリーヌ", "2030/12/17 14:59:59", 27, 0, 1, -363.0, "2015/12/17 15:00:00", 0.0);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (27003, 1, "ここにさらなる力を得るための\nアイテムが眠っているみたい！\nどんどん挑戦して\n強くなっちゃいましょ！", 0, 0.0, 1, 106001, "キャル", "2030/12/17 14:59:59", 27, 0, 1, -363.0, "2015/12/17 15:00:00", 0.0);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (27004, 1, "こちらにさらなる力を得る\nためのアイテムが眠っている\nようです。主さま、どこから\n挑戦いたしましょう。", 0, 0.0, 1, 105901, "コッコロ", "2030/12/17 14:59:59", 27, 0, 1, -363.0, "2015/12/17 15:00:00", 0.0);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (28001, 1, "ようこそ！\n皆さんの素敵な出会いを\nギルド管理協会が\nお手伝いします！", 0, 0.0, 1, 190801, "カリン", "2030/12/17 14:59:59", 28, 0, 1, -363.0, "2019/09/24 15:00:00", 0.0);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (28002, 1, "ギルド管理協会です\nフレンドに関しては\nこちらでご確認ください", 0, 0.0, 2, 190801, "カリン", "2030/12/17 14:59:59", 28, 0, 1, -363.0, "2019/09/24 15:00:00", 0.0);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (29001, 1, "こちらがフレンドの\n皆さんです\n素敵な関係を\n築いてくださいね！", 0, 0.0, 3, 190801, "カリン", "2030/12/17 14:59:59", 29, 0, 1, -409.0, "2019/09/24 15:00:00", 0.0);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (29002, 1, "こちらの一覧で\nフレンドのプロフィールを\n確認できますよ", 0, 0.0, 4, 190801, "カリン", "2030/12/17 14:59:59", 29, 0, 1, -409.0, "2019/09/24 15:00:00", 0.0);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (30001, 1, "フレンド管理は\nこちらになります\n新しいフレンドとの出会いを\n楽しんでくださいね！", 0, 0.0, 5, 190801, "カリン", "2030/12/17 14:59:59", 30, 0, 1, -409.0, "2019/09/24 15:00:00", 0.0);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (30002, 1, "フレンドの申請や\n承認ができますよ\nどうぞ、良き交流を！", 0, 0.0, 6, 190801, "カリン", "2030/12/17 14:59:59", 30, 0, 1, -409.0, "2019/09/24 15:00:00", 0.0);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (31001, 1, "バトルをして力比べを\nしてみましょう！\n実力が試されますね、\n頑張ってください！", 0, 0.0, 7, 190801, "カリン", "2030/12/17 14:59:59", 31, 0, 1, -409.0, "2019/10/31 12:00:00", 0.0);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (31002, 1, "気になるパーティと\nバトルをしてみましょう！\nどちらが勝利するのか、\n私も楽しみにしていますね", 0, 0.0, 8, 190801, "カリン", "2030/12/17 14:59:59", 31, 0, 1, -409.0, "2019/10/31 12:00:00", 0.0);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (32001, 1, "ルーキーの皆さんのために\n特別なミッションを\nご用意いたしました！\nぜひ、挑戦してください！", 0, 0.0, 1, 190801, "カリン", "2020/01/04 4:59:59", 32, 0, 1, -409.0, "2019/12/20 5:00:00", 0.0);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (32002, 1, "期間限定のキャンペーンを\n開催中です！\nミッションにチャレンジ\nしましょう！", 0, 0.0, 2, 190801, "カリン", "2020/01/04 4:59:59", 32, 0, 1, -409.0, "2019/12/20 5:00:00", 0.0);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (33001, 1, "フレンドになって\n初心者の方を応援しましょう！\n素敵な報酬が待っていますよ！", 0, 0.0, 3, 190801, "カリン", "2020/01/04 4:59:59", 33, 0, 1, -409.0, "2019/12/20 5:00:00", 0.0);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (33002, 1, "期間限定のキャンペーンを\n開催中です！\nミッションにチャレンジ\nしましょう！", 0, 0.0, 4, 190801, "カリン", "2020/01/04 4:59:59", 33, 0, 1, -409.0, "2019/12/20 5:00:00", 0.0);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (34001, 1, "お疲れ様でした！\nミッションの報酬の受け取りは\nこちらからできますよ！", 0, 0.0, 5, 190801, "カリン", "2020/01/10 11:59:59", 34, 0, 1, -409.0, "2020/01/04 5:00:00", 0.0);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (34002, 1, "ミッション報酬の受け取りは\nこちら！\n受け取り漏れの無いように\n気を付けてくださいね！", 0, 0.0, 6, 190801, "カリン", "2020/01/10 11:59:59", 34, 0, 1, -409.0, "2020/01/04 5:00:00", 0.0);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (38001, 2, "過去のストーリーイベントを\n楽しめちゃいますよ！\n遊んだことのないものがあれば\n一緒にやってみましょう♪", 0, 0.0, 1, 105801, "ペコリーヌ", "2030/12/17 14:59:59", 38, 0, 1, -458.0, "2015/12/17 15:00:00", 5.3);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (38002, 2, "これまでのイベントで登場した\n限定キャラを仲間にできたり\nメモリーピースが手に入る\nみたいですよ。やばいですね☆", 0, 0.0, 2, 105801, "ペコリーヌ", "2030/12/17 14:59:59", 38, 0, 1, -458.0, "2015/12/17 15:00:00", 6.5);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (39005, 3, "", 0, 9999.0, 0, 105801, "ペコリーヌ", "2020/04/08 23:59:59", 39, 0, 3, 9999.0, "2020/04/01", 0.0);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (40001, 1, "これまでに出題された\n問題を振り返ることが\nできますよ\n復習は大切です♪", 0, 0.0, 2, 190801, "カリン", "2030/12/17 14:59:59", 40, 0, 1, -430.0, "2015/12/17 15:00:00", 0.0);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (41001, 1, "ここでは腕試しが\nできるんですって。\n自分の実力を測るのに、\nちょうどよさそうね。", 0, 0.0, 1, 106401, "シェフィ", "2030/12/17 14:59:59", 41, 2104010, 1, -363.0, "2015/12/17 15:00:00", 0.0);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (41002, 1, "ここで腕試しを\nしていきましょう！\n全力全開、\nがんばっちゃいますよ～！", 0, 0.0, 1, 105801, "ペコリーヌ", "2030/12/17 14:59:59", 41, 0, 1, -363.0, "2015/12/17 15:00:00", 0.0);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (41003, 1, "ここで腕試しが\nできるみたいね。\n試してみるのも\nいいんじゃない？", 0, 0.0, 1, 106001, "キャル", "2030/12/17 14:59:59", 41, 0, 1, -363.0, "2015/12/17 15:00:00", 0.0);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (41004, 1, "腕試しができるようです。\nここで練習を重ね、実戦に\n活かしてまいりましょう。", 0, 0.0, 1, 105901, "コッコロ", "2030/12/17 14:59:59", 41, 0, 1, -363.0, "2015/12/17 15:00:00", 0.0);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (42001, 1, "訓練の成果に応じて、\n報酬がもらえるそうです。\n共に励んでいきましょう。", 0, 0.0, 1, 105901, "コッコロ", "2030/12/17 14:59:59", 42, 0, 1, -416.5, "2015/12/17 15:00:00", 0.0);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (42002, 1, "目標を達成すれば、\n報酬がもらえるみたい。\n頑張り甲斐があるわね。", 0, 0.0, 1, 106401, "シェフィ", "2030/12/17 14:59:59", 42, 2104010, 1, -416.5, "2015/12/17 15:00:00", 0.0);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (42003, 1, "腕試しをがんばれば、\n報酬がもらえますよ。\n挑戦していきましょう☆", 0, 0.0, 1, 105801, "ペコリーヌ", "2030/12/17 14:59:59", 42, 0, 1, -416.5, "2015/12/17 15:00:00", 0.0);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (42004, 1, "ミッションを達成すると、\n報酬が出るんですって。\n一緒にやってみましょ！", 0, 0.0, 1, 106001, "キャル", "2030/12/17 14:59:59", 42, 0, 1, -416.5, "2015/12/17 15:00:00", 0.0);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (43001, 1, "ここからアリーナに\n挑戦できますよ！\n編成を工夫してライバルに\n挑んじゃいましょう！", 0, 0.0, 1, 105801, "ペコリーヌ", "2030/12/17 14:59:59", 43, 0, 1, -363.0, "2015/12/17 15:00:00", 0.0);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (43002, 1, "こちらからアリーナに\n挑戦することができます。\n主さまらしい編成で\nライバルに挑みましょう。", 0, 0.0, 1, 105901, "コッコロ", "2030/12/17 14:59:59", 43, 0, 1, -363.0, "2015/12/17 15:00:00", 0.0);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (43003, 1, "ここからアリーナに\n挑戦できるわよ！\nしっかり編成を考えて\nライバルに挑みなさい！", 0, 0.0, 1, 106001, "キャル", "2030/12/17 14:59:59", 43, 0, 1, -363.0, "2015/12/17 15:00:00", 0.0);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (43004, 1, "ミッションをクリアすると報酬が\n受け取れるわ。ジャンジャン\nクリアしてバリバリ強化して\nあげなさい♪", 0, 0.0, 1, 123001, "アメス", "2030/12/17 14:59:59", 44, 0, 1, -416.5, "2015/12/17 15:00:00", 0.0);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (43005, 1, "ぼんやりしてる場合じゃないわ。\n早くミッションをクリアして\n報酬を受け取ってきなさい！", 0, 0.0, 2, 123001, "アメス", "2030/12/17 14:59:59", 44, 0, 1, -416.5, "2015/12/17 15:00:00", 0.0);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (43006, 2, "ちょっとあんた、報酬が\n受け取れるじゃない！\n忘れずにチェックなさい。\nアメス様との約束よ？", 0, 0.0, 3, 123001, "アメス", "2030/12/17 14:59:59", 45, 0, 1, -416.5, "2015/12/17 15:00:00", 5.79);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (46001, 1, "はい、お疲れさま。\nここではマスタリーチケットを\n使って、マスタリー強化素材を\n手に入れることができるわよ。", 0, 0.0, 1, 123001, "アメス", "2030/12/17 14:59:59", 46, 0, 1, -371.5, "2015/12/17 15:00:00", 0.0);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (47001, 2, "呼ばれて飛び出てお姉ちゃんだよ♪\nたとえ火の中、水の中、迷宮の中っ\nこのダンジョンを踏破できるよう\n弟くんを応援してあげるからねっ♪", 0, 0.0, 1, 104901, "シズル", "2030/12/17 14:59:59", 47, 0, 2, -416.5, "2015/12/17 15:00:00", 0.0);
INSERT INTO `v1_bd5ce592b82d2fa93ffb0076ffa3298ba22b4a0bd7dce85190cf9012146220e1` VALUES (47002, 2, "ほんとーに不思議な場所ですね～\nお兄ちゃんが冒険を頑張れるよう\nおまじないをかけてあげますねっ\nフレーフレー、お・兄・ちゃんっ♪", 0, 0.0, 1, 101101, "リノ", "2030/12/17 14:59:59", 47, 0, 1, -416.5, "2015/12/17 15:00:00", 9.32);
